package com.hospital.management.controller.appointment;import com.hospital.management.model.*;import com.hospital.management.service.*;import com.hospital.management.service.impl.AppointmentServiceImpl;import javax.servlet.*;import javax.servlet.annotation.WebServlet;import javax.servlet.http.*;import java.io.IOException;
@WebServlet("/appointments/edit")public class AppointmentEditServlet extends HttpServlet {private final AppointmentService service;public AppointmentEditServlet(){this(new AppointmentServiceImpl());}public AppointmentEditServlet(AppointmentService s){service=s;}protected void doGet(HttpServletRequest q,HttpServletResponse r)throws ServletException,IOException{Long id=AppointmentRequest.id(q.getParameter("id"));Appointment a=id==null?null:service.getAppointment(id,AppointmentRequest.user(q)).orElse(null);if(a==null){r.sendError(404);return;}AppointmentForm f=new AppointmentForm();f.setAppointmentId(id);f.setReason(a.getReason());f.setNotes(a.getNotes());q.setAttribute("appointmentForm",f);q.setAttribute("appointment",a);q.setAttribute("formMode","EDIT");q.getRequestDispatcher("/WEB-INF/views/appointments/form.jsp").forward(q,r);}protected void doPost(HttpServletRequest q,HttpServletResponse r)throws ServletException,IOException{AppointmentForm f=AppointmentRequest.form(q);ServiceResult<Void>x=service.updateAppointment(f,AppointmentRequest.audit(q),AppointmentRequest.user(q));if(x.isSuccess()){r.sendRedirect(q.getContextPath()+"/appointments/view?id="+f.getAppointmentId()+"&message=updated");return;}q.setAttribute("appointmentForm",f);q.setAttribute("errors",x.getErrors());q.setAttribute("errorMessage",x.getMessage());q.setAttribute("formMode","EDIT");q.getRequestDispatcher("/WEB-INF/views/appointments/form.jsp").forward(q,r);}}
